function setPool(address localToken, address pool) external onlyTokenAdmin(localToken) {
  // The pool has to support the token, but we want to allow removing the pool, so we only check
  // if the pool supports the token if it is not address(0).
  if (pool != address(0) && !IPoolV1(pool).isSupportedToken(localToken)) {
    revert InvalidTokenPoolToken(localToken);
  }

  TokenConfig storage config = s_tokenConfig[localToken];

  address previousPool = config.tokenPool;
  config.tokenPool = pool;

  if (previousPool != pool) {
    emit PoolSet(localToken, previousPool, pool);
  }
}

function _getMultiAssetDepositData(
    ERC20 depositAsset,
    uint256 assets
)
    internal
    view
    returns (uint256 assetsConvertedToAsset, uint256 assetsConvertedToAssetWithFeeRemoved, uint32 position)
{
    AlternativeAssetData memory assetData = alternativeAssetData[depositAsset];
    if (!assetData.isSupported) revert CellarWithMultiAssetDeposit__AlternativeAssetNotSupported();

    // Convert assets from depositAsset to asset.
    assetsConvertedToAsset = priceRouter.getValue(depositAsset, assets, asset);

    // Collect alternative asset fee.
    assetsConvertedToAssetWithFeeRemoved = assetsConvertedToAsset.mulDivDown(1e8 - assetData.depositFee, 1e8);

    position = assetData.holdingPosition;
}

function permitAndStake(
    address hypervisor,
    address vault,
    Permit calldata permit,
    bytes calldata permission
) public {
    // get staking token
    address stakingToken = IHypervisor(hypervisor).getHypervisorData().stakingToken;
    // permit transfer
    IERC20Permit(stakingToken).permit(
        permit.owner,
        permit.spender,
        permit.value,
        permit.deadline,
        permit.v,
        permit.r,
        permit.s
    );
    // transfer tokens
    TransferHelper.safeTransferFrom(stakingToken, msg.sender, vault, permit.value);
    // stake
    IHypervisor(hypervisor).stake(vault, permit.value, permission);
}

function initializeLastMintTimestamp()
        external
        onlyRole(CONTRACT_GOVERNANCE_ROLE)
        gacPausable
    {
        require(
            lastMintTimestamp == 0,
            "CitadelMinter: last mint timestamp already initialized"
        );
        uint256 globalStartTimestamp = ISupplySchedule(supplySchedule)
            .globalStartTimestamp();

        require(
            globalStartTimestamp != 0,
            "CitadelMinter: supply schedule start not initialized"
        );
        lastMintTimestamp = globalStartTimestamp;
    }

function collectLegacyWithSig(
    Types.LegacyCollectParams calldata collectParams,
    Types.EIP712Signature calldata signature
)
    external
    override
    whenNotPaused
    onlyProfileOwnerOrDelegatedExecutor(signature.signer, collectParams.collectorProfileId)
    returns (uint256)
{
    MetaTxLib.validateLegacyCollectSignature(signature, collectParams);
    return
        LegacyCollectLib.collect({
            collectParams: collectParams,
            transactionExecutor: signature.signer,
            collectorProfileOwner: ownerOf(collectParams.collectorProfileId),
            collectNFTImpl: this.getLegacyCollectNFTImpl()
        });
}

function actWithSig(
    Types.PublicationActionParams calldata publicationActionParams,
    Types.EIP712Signature calldata signature
)
    external
    override
    whenNotPaused
    onlyProfileOwnerOrDelegatedExecutor(signature.signer, publicationActionParams.actorProfileId)
    returns (bytes memory)
{
    MetaTxLib.validateActSignature(signature, publicationActionParams);
    return
        ActionLib.act({
            publicationActionParams: publicationActionParams,
            transactionExecutor: signature.signer,
            actorProfileOwner: ownerOf(publicationActionParams.actorProfileId)
        });
}

function _permitTransferFrom(
    PermitTransferFrom memory permit,
    SignatureTransferDetails calldata transferDetails,
    address owner,
    bytes32 dataHash,
    bytes calldata signature
) private {
    uint256 requestedAmount = transferDetails.requestedAmount;

    if (block.timestamp > permit.deadline) revert SignatureExpired(permit.deadline);
    if (requestedAmount > permit.permitted.amount) revert InvalidAmount(permit.permitted.amount);

    _useUnorderedNonce(owner, permit.nonce);

    signature.verify(_hashTypedData(dataHash), owner);

    ERC20(permit.permitted.token).safeTransferFrom(owner, transferDetails.to, requestedAmount);
}

function flashLoanSimple(
  address receiverAddress,
  address asset,
  uint256 amount,
  bytes calldata params,
  uint16 referralCode
) public virtual override {
  DataTypes.FlashloanSimpleParams memory flashParams = DataTypes.FlashloanSimpleParams({
    receiverAddress: receiverAddress,
    asset: asset,
    amount: amount,
    params: params,
    referralCode: referralCode,
    flashLoanPremiumToProtocol: _flashLoanPremiumToProtocol,
    flashLoanPremiumTotal: _flashLoanPremiumTotal
  });
  FlashLoanLogic.executeFlashLoanSimple(_reserves[asset], flashParams);
}

function _updateImpl(bytes32 id, address newAddress) internal {
  address proxyAddress = _addresses[id];
  InitializableImmutableAdminUpgradeabilityProxy proxy;
  bytes memory params = abi.encodeWithSignature('initialize(address)', address(this));

  if (proxyAddress == address(0)) {
    proxy = new InitializableImmutableAdminUpgradeabilityProxy(address(this));
    _addresses[id] = proxyAddress = address(proxy);
    proxy.initialize(newAddress, params);
    emit ProxyCreated(id, proxyAddress, newAddress);
  } else {
    proxy = InitializableImmutableAdminUpgradeabilityProxy(payable(proxyAddress));
    proxy.upgradeToAndCall(newAddress, params);
  }
}

function initialize(address underlying_,
                        ComptrollerInterface comptroller_,
                        InterestRateModel interestRateModel_,
                        uint initialExchangeRateMantissa_,
                        string memory name_,
                        string memory symbol_,
                        uint8 decimals_) public {
        // CToken initialize does the bulk of the work
        super.initialize(comptroller_, interestRateModel_, initialExchangeRateMantissa_, name_, symbol_, decimals_);

        // Set underlying and sanity check it
        underlying = underlying_;
        EIP20Interface(underlying).totalSupply();
    }

function executeMatchAdvancedOrders(
    SeaportInterface seaport,
    AdvancedOrder[] calldata orders,
    CriteriaResolver[] calldata criteriaResolvers,
    Fulfillment[] calldata fulfillments
)
    external
    payable
    override
    isOperator
    isNotPaused
    returns (Execution[] memory executions)
{
    // Call matchAdvancedOrders on Seaport and return the sequence of
    // transfers performed as part of matching the given orders.
    executions = seaport.matchAdvancedOrders{ value: msg.value }(
        orders,
        criteriaResolvers,
        fulfillments,
        msg.sender
    );
}

function transferOwnership(address newPotentialOwner) external override {
    // Ensure the caller is the owner.
    if (msg.sender != _owner) {
        revert CallerIsNotOwner();
    }
    // Ensure the new potential owner is not an invalid address.
    if (newPotentialOwner == address(0)) {
        revert OwnerCanNotBeSetAsZero();
    }

    // Emit an event indicating that the potential owner has been updated.
    emit PotentialOwnerUpdated(newPotentialOwner);

    // Set the new potential owner as the potential owner.
    _potentialOwner = newPotentialOwner;
}

function acceptOwnership() external override {
    // Ensure the caller is the potential owner.
    if (msg.sender != _potentialOwner) {
        revert CallerIsNotPotentialOwner();
    }

    // Emit an event indicating that the potential owner has been cleared.
    emit PotentialOwnerUpdated(address(0));

    // Clear the current new potential owner
    delete _potentialOwner;

    // Emit an event indicating ownership has been transferred.
    emit OwnershipTransferred(_owner, msg.sender);

    // Set the caller as the owner of this contract.
    _owner = msg.sender;
}

function _delegate(address delegator, address delegatee) internal virtual {
    DelegateInfo memory delegateInfo = delegateInfo(delegator);
    uint256 delegatorBalance = balanceOf(delegator);

    _delegates[delegator] = DelegateInfo(delegatee, SafeCast.toUint96(block.timestamp));

    emit DelegateChanged(delegator, delegateInfo.delegate, delegatee);

    zeroExVotes.moveVotingPower(
        delegateInfo.delegate,
        delegatee,
        delegatorBalance,
        0,
        delegateInfo.balanceLastUpdated,
        0,
        delegatorBalance
    );
}

function getOrderFromOrderParam(OrderParam memory orderParam, OrderAddressSet memory orderAddressSet)
    internal
    pure
    returns (Order memory order)
    {
        order.trader = orderParam.trader;
        order.baseTokenAmount = orderParam.baseTokenAmount;
        order.quoteTokenAmount = orderParam.quoteTokenAmount;
        order.gasTokenAmount = orderParam.gasTokenAmount;
        order.data = orderParam.data;
        order.baseToken = orderAddressSet.baseToken;
        order.quoteToken = orderAddressSet.quoteToken;
        order.relayer = orderAddressSet.relayer;
    }

function reverseAddressCallback(
    bytes calldata response,
    bytes calldata extraData
)
    external
    pure
    returns (
        string memory primary,
        address resolver,
        address reverseResolver
    )
{
    ReverseArgs memory args;
    (args, primary, resolver) = abi.decode(
        extraData,
        (ReverseArgs, string, address)
    );
    bytes memory primaryAddress;
    if (args.coinType == COIN_TYPE_ETH) {
        address addr = abi.decode(response, (address));
        primaryAddress = abi.encodePacked(addr);
    } else {
        primaryAddress = abi.decode(response, (bytes));
    }
    if (!BytesUtils.equals(args.lookupAddress, primaryAddress)) {
        revert ReverseAddressMismatch(primary, primaryAddress);
    }
    reverseResolver = args.resolver;
}

function LiquidityProviderIncompleteSellError(
    address providerAddress,
    address makerToken,
    address takerToken,
    uint256 sellAmount,
    uint256 boughtAmount,
    uint256 minBuyAmount
) internal pure returns (bytes memory) {
    return
        abi.encodeWithSelector(
            bytes4(
                keccak256("LiquidityProviderIncompleteSellError(address,address,address,uint256,uint256,uint256)")
            ),
            providerAddress,
            makerToken,
            takerToken,
            sellAmount,
            boughtAmount,
            minBuyAmount
        );
}

function getFeeCollectorAddress(
    address controller,
    bytes32 initCodeHash,
    bytes32 poolId
) internal pure returns (address payable feeCollectorAddress) {
    // Compute the CREATE2 address for the fee collector.
    return
        address(
            uint256(
                keccak256(
                    abi.encodePacked(
                        bytes1(0xff),
                        controller,
                        poolId, // pool ID is salt
                        initCodeHash
                    )
                )
            )
        );
}

function _executeFillLimitOrderCall(ExecuteState memory state) private returns (bytes memory returnResult) {
    LibNativeOrder.LimitOrder memory order;
    LibSignature.Signature memory signature;
    uint128 takerTokenFillAmount;

    bytes memory args = _extractArgumentsFromCallData(state.mtx.callData);
    (order, signature, takerTokenFillAmount) = abi.decode(
        args,
        (LibNativeOrder.LimitOrder, LibSignature.Signature, uint128)
    );

    return
        _callSelf(
            state.hash,
            abi.encodeWithSelector(
                INativeOrdersFeature._fillLimitOrder.selector,
                order,
                signature,
                takerTokenFillAmount,
                state.mtx.signer, // taker is mtx signer
                msg.sender
            )
        );
}

constructor(address underlying_,
                ComptrollerInterface comptroller_,
                InterestRateModel interestRateModel_,
                uint initialExchangeRateMantissa_,
                string memory name_,
                string memory symbol_,
                uint8 decimals_,
                address payable admin_) {
        // Creator of the contract is admin during initialization
        admin = payable(msg.sender);

        // Initialize the market
        initialize(underlying_, comptroller_, interestRateModel_, initialExchangeRateMantissa_, name_, symbol_, decimals_);

        // Set the proper admin now that initialization is done
        admin = admin_;
    }

