        admin = payable(msg.sender);

        initialize(comptroller_, interestRateModel_, initialExchangeRateMantissa_, name_, symbol_, decimals_);

        // Set the proper admin now that initialization is done
        admin = admin_;
    }

function changeDelegatedExecutorsConfigWithSig(
    uint256 delegatorProfileId,
    address[] calldata delegatedExecutors,
    bool[] calldata approvals,
    uint64 configNumber,
    bool switchToGivenConfig,
    Types.EIP712Signature calldata signature
) external override whenNotPaused onlyProfileOwner(signature.signer, delegatorProfileId) {
    MetaTxLib.validateChangeDelegatedExecutorsConfigSignature(
        signature,
        delegatorProfileId,
        delegatedExecutors,
        approvals,
        configNumber,
        switchToGivenConfig
    );
    ProfileLib.changeGivenDelegatedExecutorsConfig(
        delegatorProfileId,
        delegatedExecutors,
        approvals,
        configNumber,
        switchToGivenConfig
    );
}

function _setFollowModule(
    uint256 profileId,
    address followModule,
    bytes calldata followModuleInitData,
    address transactionExecutor
) private {
    StorageLib.getProfile(profileId).followModule = followModule;
    bytes memory followModuleReturnData;
    if (followModule != address(0)) {
        followModuleReturnData = _initFollowModule(
            profileId,
            transactionExecutor,
            followModule,
            followModuleInitData
        );
    }
    emit Events.FollowModuleSet(
        profileId,
        followModule,
        followModuleInitData,
        followModuleReturnData,
        transactionExecutor,
        block.timestamp
    );
}

function multiAssetDeposit(
    ERC20 depositAsset,
    uint256 assets,
    address receiver
) public nonReentrant returns (uint256 shares) {
    // Convert assets from depositAsset to asset.
    (
        uint256 assetsConvertedToAsset,
        uint256 assetsConvertedToAssetWithFeeRemoved,
        uint32 position
    ) = _getMultiAssetDepositData(depositAsset, assets);

    shares = _deposit(
        depositAsset,
        assets,
        assetsConvertedToAsset,
        assetsConvertedToAssetWithFeeRemoved,
        position,
        receiver
    );

    emit MultiAssetDeposit(msg.sender, receiver, address(depositAsset), assets, shares);
}

function proposalInformation(
    uint256 proposalId
)
    external
    view
    returns (
        address proposer,
        uint256 voteSnapshotTimestamp,
        uint256 votingStartTime,
        uint256 endTimestamp,
        uint256 crossChainVoteCollectionEndTimestamp,
        uint256 totalVotes,
        uint256 forVotes,
        uint256 againstVotes,
        uint256 abstainVotes
    )
{
    Proposal storage proposal = proposals[proposalId];

    proposer = proposal.proposer;
    voteSnapshotTimestamp = proposal.voteSnapshotTimestamp;
    votingStartTime = proposal.votingStartTime;
    endTimestamp = proposal.votingEndTime;
    crossChainVoteCollectionEndTimestamp = proposal
        .crossChainVoteCollectionEndTimestamp;
    totalVotes = proposal.totalVotes;
    forVotes = proposal.forVotes;
    againstVotes = proposal.againstVotes;
    abstainVotes = proposal.abstainVotes;
}

function getFutureUnlockedRewards(uint256 timestamp)
        public
        view
        override
        returns (uint256 unlockedRewards)
    {
        // get reward amount remaining
        uint256 remainingRewards = IERC20(_hypervisor.rewardToken).balanceOf(_hypervisor.rewardPool);
        // calculate reward available based on state
        unlockedRewards = calculateUnlockedRewards(
            _hypervisor.rewardSchedules,
            remainingRewards,
            _hypervisor.rewardSharesOutstanding,
            timestamp
        );
        // explicit return
        return unlockedRewards;
    }
